/**
 * Generate plan test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generatePlanTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generatePlanTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generatePlanTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<PlanCreateRequest> = {}
): PlanCreateRequest {
  let baseData: PlanCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalPlanFixture };
      break;

    case 'complete':
      baseData = { ...completePlanFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidPlanFixture } as PlanCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniquePlanFixture,
        name: `Test Plan ${generateUniqueId()}`,
        code: `TST-${generateUniqueId()}`.substring(0, 20),
      };
      break;

    default:
      baseData = { ...completePlanFixture };
  }

  return { ...baseData, ...overrides };
}

/**
 * Generate multiple plan fixtures
 *
 * @param count - Number of fixtures to generate
 * @param pattern - The test data pattern to use as base
 * @param modifier - Optional function to modify each fixture
 * @returns Array of generated test data
 *
 * @example
 * ```typescript
 * // Generate 5 unique fixtures
 * const fixtures = generateMultiplePlanFixtures(5, 'unique');
 *
 * // Generate fixtures with sequential numbering
 * const numbered = generateMultiplePlanFixtures(3, 'complete', (data, index) => ({
 *   ...data,
 *   name: `Plan #${index + 1}`,
 * }));
 * ```
 */
export function generateMultiplePlanFixtures(
  count: number,
  pattern: TestDataPattern = 'unique',
  modifier?: (data: PlanCreateRequest, index: number) => PlanCreateRequest
): PlanCreateRequest[] {
  const fixtures: PlanCreateRequest[] = [];

  for (let i = 0; i < count; i++) {
    let fixture = generatePlanTestData(pattern);

    if (modifier) {
      fixture = modifier(fixture, i);
    } else if (pattern === 'unique') {
      // Add index to ensure uniqueness even with same timestamp
      fixture.name = `Test Plan ${generateUniqueId()}-${i}`;
      fixture.code = `TST-${i}-${generateUniqueId()}`.substring(0, 20);
    }

    fixtures.push(fixture);
  }

  return fixtures;
}

